#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int longestOnes(vector<int>& nums, int k) {
        int left = 0;
        for (int right = 0; right < nums.size(); right++) {
            k -= 1 - nums[right];
            if (k < 0) {
                k += 1 - nums[left];
                left++;
            }
        }
        return nums.size() - left;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    int k;
    if (!(cin >> k)) return 0;
    Solution sol;
    int ans = sol.longestOnes(nums, k);
    cout << ans << "\n";
    return 0;
}
